def run_test():
    """Ejecuta la simulación de comparación biométrica."""
    print("🚀 Iniciando script de prueba...", flush=True)
    
    if "..." in imagen_base64:
        print("❌ ERROR: Debes reemplazar el valor de 'imagen_base64' con una imagen real.", flush=True)
        return

    if len(imagen_base64) < 100:
        print("⚠️ ADVERTENCIA: El string base64 parece muy corto. Asegúrate de haberlo copiado completo.", flush=True)

    # Importación diferida para mostrar mensajes antes de cargar TensorFlow/DeepFace
    print("⏳ Cargando librerías de IA (esto puede tardar unos segundos)...", flush=True)
    try:
        from app.services.face_service import get_face_embedding, verify_face_match
    except ImportError as e:
        print(f"❌ Error al importar librerías: {e}", flush=True)
        return

    # 1. Simula el LOGIN: Genera un embedding desde la imagen de prueba.
    print("👤 Generando embedding para la imagen de prueba...", flush=True)
    emb_login = get_face_embedding(imagen_base64)
    
    if not emb_login:
        print("❌ No se pudo generar el embedding. Revisa si la imagen tiene un rostro visible.", flush=True)
        return
    print("   -> ✅ Embedding generado correctamente.", flush=True)

    # 2. La prueba de fuego: Compara el embedding de la BD con el de la imagen.
    print("\n🔥 Comparando rostros...", flush=True)
    try:
        resultado = verify_face_match(string_para_bd, emb_login)
    except Exception as e:
        print(f"❌ Error crítico durante la comparación: {e}", flush=True)
        return

    # 3. Muestra el resultado final.
    print("-" * 30, flush=True)
    if resultado:
        print("✅ ¡PRUEBA EXITOSA! El rostro coincide.", flush=True)
    else:
        print("❌ PRUEBA FALLIDA. El rostro NO coincide.", flush=True)
    print("-" * 30, flush=True)

if __name__ == "__main__":
    run_test()